:root {
  --accent-color: #c09f30;
  --accent-color-dark: #a18321;
  --bg-primary: #f9f9f9; 
  --bg-chat-container: #ffffff;
  --text-primary: #1a1a1a; 
  --text-secondary: #444;
  --text-faded: #888;
  --border-color: #f0f0f0; 
  --sidebar-bg: #fdfdfd;
  --sidebar-border: #f0f0f0;
  --hover-bg: #f5f5f5;
  --active-session-bg: linear-gradient(to right, #fdf5d9, #fff);
  --user-msg-bg: #f0f2f5; 
  --user-msg-text-color: var(--text-primary);
  --bot-msg-bg: linear-gradient(to right, #fdf5d9, #f9eebf);
  --bot-msg-border: transparent;
  --bot-text-color: #3a2d00;
  --bot-code-bg: #fafafa;
  --bot-code-border: #f0f0f0;
  --input-bg: #f0f2f5;
  --shadow-color: rgba(161, 131, 33, 0.15); 
  --header-bg: rgba(255, 255, 255, 0.85); 
  --header-shadow: 0 2px 4px rgba(0,0,0,0.02);
  --header-icon-color: var(--text-secondary);
  --header-title-color: var(--text-primary);
  --scrollbar-thumb: #ccc;
  --scrollbar-track: #f1f1f1;
}
.header-btn:hover { background: rgba(0,0,0,0.05); }
.message.user { color: var(--user-msg-text-color); }
.bot { color: var(--bot-text-color); }

body.theme-dark {
  --bg-primary: linear-gradient(to bottom right, #101010, #0d0d0d);
  --bg-chat-container: #121212;
  --text-primary: #e0e0e0;
  --text-secondary: #b3b3b3;
  --text-faded: #777;
  --border-color: #222;
  --sidebar-bg: #0d0d0d;
  --sidebar-border: #222;
  --hover-bg: #1f1f1f;
  --active-session-bg: linear-gradient(to right, #4d3d0a, #3b2f08);
  --user-msg-bg: #282828;
  --user-msg-text-color: var(--text-primary);
  --bot-msg-bg: #1E1E1E; 
  --bot-msg-border: transparent;
  --bot-text-color: #e0e0e0;
  --bot-code-bg: #1a1a1a;
  --bot-code-border: #2a2a2a;
  --input-bg: #1E1E1E;
  --shadow-color: rgba(218, 165, 32, 0.08);
  --header-bg: rgba(18, 18, 18, 0.85); 
  --header-shadow: 0 4px 12px rgba(0,0,0,0.15);
  --header-icon-color: #e1e1e1;
  --header-title-color: #e1e1e1;
  --scrollbar-thumb: #444;
  --scrollbar-track: #222;
}
body.theme-dark .header-btn:hover { background: rgba(255,255,255,0.1); }
body.theme-dark #submit-button { color: #3a2d00; }

body.theme-ocean {
