}
body.theme-forest .header-btn:hover { background: rgba(255,255,255,0.1); }
body.theme-forest #submit-button { background: linear-gradient(to right, var(--accent-color), #81C784); color: #1a1a1a; }
body.theme-forest #new-chat-btn { border-color: var(--accent-color); }
body.theme-forest #new-chat-btn:hover { background: var(--accent-color); color: #fff; }

body.theme-sakura-light {
  --accent-color: #FFB7C5; 
  --accent-color-dark: #E6A8B5;
  --bg-primary: #FFF9FA;
  --bg-chat-container: #ffffff;
  --text-primary: #333;
  --text-secondary: #555;
  --text-faded: #999;
  --border-color: #F5F0F1;
  --sidebar-bg: #FFFDFE;
  --sidebar-border: #F5F0F1;
  --hover-bg: #FDF5F6;
  --active-session-bg: linear-gradient(to right, #FFF0F5, #fff);
