  --hover-bg: #322F43;
  --active-session-bg: linear-gradient(to right, #3A364F, #2F2C40);
  --user-msg-bg: #D68096;
  --user-msg-text-color: #FFFFFF;
  --bot-msg-bg: #1F1D2B;
  --bot-msg-border: #322F43;
  --bot-text-color: #E0E0E0;
  --input-bg: #1F1D2B;
  --shadow-color: rgba(214, 128, 150, 0.1);
  --header-bg: rgba(38, 35, 53, 0.85); 
  --header-shadow: 0 4px 12px rgba(0,0,0,0.15);
  --scrollbar-thumb: #D68096;
  --scrollbar-track: #1F1D2B;
}
body.theme-sakura-dark .header-btn:hover { background: rgba(255,255,255,0.1); }
body.theme-sakura-dark #submit-button { color: #1F1D2B; }

body.theme-cyberpunk-light {
  --accent-color: #00F0FF; 
  --accent-color-dark: #00C0CC;
  --bg-primary: #E0E0E0;
  --bg-chat-container: #F5F5F5;
  --text-primary: #0A0A0A;
  --text-secondary: #333;
  --text-faded: #666;
  --border-color: #DCDCDC;
  --sidebar-bg: #F0F0F0;
  --sidebar-border: #DCDCDC;
  --hover-bg: #E0E0E0;
  --active-session-bg: linear-gradient(to right, #E0FFFF, #F5F5F5);
  --user-msg-bg: #00F0FF;
  --user-msg-text-color: #000;
  --bot-msg-bg: #F5F5F5;
  --bot-msg-border: #E0E0E0;
  --bot-text-color: #0A0A0A;
  --input-bg: #E0E0E0;
  --shadow-color: rgba(0, 240, 255, 0.2);
  --header-bg: rgba(245, 245, 245, 0.85); 
  --header-shadow: 0 2px 4px rgba(0,0,0,0.02);
  --scrollbar-thumb: #00F0FF;
  --scrollbar-track: #f1f1f1;
}
body.theme-cyberpunk-light #submit-button { color: #000; }
body.theme-cyberpunk-light .header-title { text-shadow: 0 0 5px var(--accent-color); }

body.theme-cyberpunk-dark {
  --accent-color: #00F0FF; 
  --accent-color-dark: #00C0CC;
  --bg-primary: #0A0A23; 
  --bg-chat-container: #0F0F2A;
  --text-primary: #E0E0E0;
  --text-secondary: #00F0FF;
  --text-faded: #FF00FF; 
  --border-color: #FF00FF;
  --sidebar-bg: #0A0A23;
  --sidebar-border: #FF00FF;
  --hover-bg: #1F1F3A;
  --active-session-bg: linear-gradient(to right, #1F1F3A, #0F0F2A);
  --user-msg-bg: #1F1F3A;
  --user-msg-text-color: #00F0FF;
  --bot-msg-bg: #0F0F2A;
  --bot-msg-border: #1F1F3A;
  --bot-text-color: #E0E0E0;
  --bot-code-bg: #0A0A23;
  --bot-code-border: #FF00FF;
  --input-bg: #1F1F3A;
  --shadow-color: rgba(0, 240, 255, 0.1);
  --header-bg: rgba(15, 15, 42, 0.85); 
  --header-shadow: 0 4px 12px rgba(0,0,0,0.15);
  --scrollbar-thumb: #00F0FF;
  --scrollbar-track: #0A0A23;
}
body.theme-cyberpunk-dark .header-btn:hover { background: rgba(255,255,255,0.1); }
body.theme-cyberpunk-dark .header-title { 
  color: var(--accent-color); 
  text-shadow: 0 0 8px var(--accent-color), 0 0 12px var(--accent-color-dark); 
  animation: flicker 0.15s infinite alternate; 
}
body.theme-cyberpunk-dark #new-chat-btn { border-color: var(--text-faded); color: var(--text-secondary); }
body.theme-cyberpunk-dark #new-chat-btn:hover { border-color: var(--accent-color); background: #1F1F3A; color: var(--accent-color); }
body.theme-cyberpunk-dark ::selection { background: var(--accent-color); color: #0A0A23; }
@keyframes flicker { from { opacity: 1; } to { opacity: 0.9; } }
body.theme-cyberpunk-dark::before {
  content: "";
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: repeating-linear-gradient( transparent 0, rgba(255, 0, 255, 0.05) 1px, rgba(0, 240, 255, 0.05) 2px, transparent 3px );
  animation: scanlines 10s linear infinite;
  pointer-events: none;
  z-index: 2000;
  opacity: 0.5;
}
@keyframes scanlines { 0% { background-position-y: 0; } 100% { background-position-y: 100px; } }

body.theme-nord-light {
  --accent-color: #5E81AC; /* Nord 10 (blue) */
