  --text-faded: #D8DEE9; /* Nord 4 */
  --border-color: #E5E9F0; /* Nord 5 */
  --sidebar-bg: #ECEFF4;
  --sidebar-border: #E5E9F0;
  --hover-bg: #E5E9F0;
  --active-session-bg: linear-gradient(to right, #E5E9F0, #fff);
