  --user-msg-bg: #4C566A;
  --user-msg-text-color: #ECEFF4;
  --bot-msg-bg: #434C5E;
  --bot-msg-border: #4C566A;
  --bot-text-color: #ECEFF4;
  --bot-code-bg: #2E3440;
  --bot-code-border: #4C566A;
  --input-bg: #434C5E;
  --shadow-color: rgba(136, 192, 208, 0.1);
  --header-bg: rgba(59, 66, 82, 0.85); 
  --header-shadow: 0 4px 12px rgba(0,0,0,0.15);
  --header-icon-color: #e1e1e1;
  --header-title-color: #e1e1e1;
  --scrollbar-thumb: #4C566A;
  --scrollbar-track: #2E3440;
}
body.theme-nord-dark .header-btn:hover { background: rgba(255,255,255,0.1); }
body.theme-nord-dark #submit-button { background: var(--accent-color); color: #2E3440; }
body.theme-nord-dark #new-chat-btn { border-color: var(--accent-color); }

