body.theme-catppuccin-dark {
  --accent-color: #89b4fa; /* Blue */
  --accent-color-dark: #a6e3a1; /* Green */
  --bg-primary: #1e1e2e; /* Base */
  --bg-chat-container: #181825; /* Mantle */
  --text-primary: #cdd6f4; /* Text */
  --text-secondary: #bac2de;
  --text-faded: #7f849c; /* Overlay0 */
  --border-color: #313244; /* Surface0 */
  --sidebar-bg: #1e1e2e;
  --sidebar-border: #313244;
  --hover-bg: #313244;
  --active-session-bg: linear-gradient(to right, #313244, #181825);
  --user-msg-bg: #313244;
  --user-msg-text-color: #cdd6f4;
  --bot-msg-bg: #181825;
  --bot-msg-border: #313244;
  --bot-text-color: #cdd6f4;
  --bot-code-bg: #1e1e2e;
  --bot-code-border: #313244;
  --input-bg: #313244;
  --shadow-color: rgba(137, 180, 250, 0.1); 
  --header-bg: rgba(30, 30, 46, 0.85); 
  --header-shadow: 0 4px 12px rgba(0,0,0,0.15);
  --header-icon-color: #cdd6f4;
  --header-title-color: #cdd6f4;
  --scrollbar-thumb: #313244;
  --scrollbar-track: #1e1e2e;
}
body.theme-catppuccin-dark .header-btn:hover { background: rgba(255,255,255,0.1); }
body.theme-catppuccin-dark #submit-button { background: var(--accent-color); color: #1e1e2e; }

body.theme-rose-pine-light {
  --accent-color: #56949f; /* Foam */
  --accent-color-dark: #907aa9; /* Iris */
  --bg-primary: #faf4ed; /* Base */
  --bg-chat-container: #fffaf3;
  --text-primary: #575279; /* Text */
  --text-secondary: #6e6a86;
  --text-faded: #9893a5; /* Subtle */
  --border-color: #f2e9de; /* Highlight Low */
  --sidebar-bg: #faf4ed;
  --sidebar-border: #f2e9de;
  --hover-bg: #f2e9de;
  --active-session-bg: linear-gradient(to right, #f2e9de, #fffaf3);
  --user-msg-bg: #56949f;
  --user-msg-text-color: #faf4ed;
  --bot-msg-bg: #f2e9de;
  --bot-msg-border: #f2e9de;
  --bot-text-color: #575279;
  --bot-code-bg: #fffaf3;
  --bot-code-border: #f2e9de;
  --input-bg: #f2e9de;
  --shadow-color: rgba(86, 148, 159, 0.15); 
  --header-bg: rgba(250, 244, 237, 0.85); 
  --header-shadow: 0 2px 4px rgba(0,0,0,0.02);
  --header-icon-color: var(--text-secondary);
  --header-title-color: var(--text-primary);
  --scrollbar-thumb: #9893a5;
  --scrollbar-track: #faf4ed;
}
body.theme-rose-pine-light #submit-button { background: var(--accent-color); color: #faf4ed; }

body.theme-rose-pine-dark {
  --accent-color: #81e0ff; /* Foam */
  --accent-color-dark: #c4a7e7; /* Iris */
  --bg-primary: #191724; /* Base */
  --bg-chat-container: #1f1d2e; /* Surface */
  --text-primary: #e0def4; /* Text */
  --text-secondary: #908caa;
  --text-faded: #6e6a86; /* Subtle */
  --border-color: #26233a; /* Overlay */
  --sidebar-bg: #191724;
  --sidebar-border: #26233a;
  --hover-bg: #26233a;
  --active-session-bg: linear-gradient(to right, #26233a, #1f1d2e);
  --user-msg-bg: #26233a;
  --user-msg-text-color: #e0def4;
  --bot-msg-bg: #1f1d2e;
  --bot-msg-border: #26233a;
  --bot-text-color: #e0def4;
  --bot-code-bg: #191724;
  --bot-code-border: #26233a;
  --input-bg: #26233a;
  --shadow-color: rgba(129, 224, 255, 0.1); 
  --header-bg: rgba(31, 29, 46, 0.85); 
  --header-shadow: 0 4px 12px rgba(0,0,0,0.15);
  --header-icon-color: #e0def4;
  --header-title-color: #e0def4;
  --scrollbar-thumb: #26233a;
  --scrollbar-track: #191724;
}
body.theme-rose-pine-dark .header-btn:hover { background: rgba(255,255,255,0.1); }
body.theme-rose-pine-dark #submit-button { background: var(--accent-color); color: #191724; }
